const prompt = (seg.veo3_prompt || '').replace(/[\\"]/g, "'").replace(/[\n\r\t]/g, ' ').trim();
if (!prompt) throw new Error('veo3_prompt 없음 (장면1)');

return [{
  json: {
    veo3Body: {
      prompt: prompt,
      imageUrls: [imageUrl],
      model: 'veo3_fast',
      generationType: 'FIRST_AND_LAST_FRAMES_2_VIDEO',
      aspect_ratio: '16:9',
      enableTranslation: false
    }
  }
}];

// 프레임 결과: NCA 응답에서 이미지 URL 추출
const data = $input.first().json;
let frameUrl = '';

if (Array.isArray(data?.response)) {
  frameUrl = data.response[0]?.file_url || '';
}
if (!frameUrl && data?.file_url) frameUrl = data.file_url;
if (!frameUrl && data?.url) frameUrl = data.url;

if (!frameUrl) {
  throw new Error('프레임 추출 실패: ' + JSON.stringify(data).substring(0, 500));
}

return [{ json: { frameUrl: frameUrl } }];

// 영상2 준비: 프레임1 결과에서 프레임 URL 가져오기
const frameUrl = $input.first().json.frameUrl || '';
if (!frameUrl) throw new Error('프레임1 URL 없음');

const seg = $('세그먼트 분리').all()[1].json;
const prompt = (seg.veo3_prompt || '').replace(/[\\"]/g, "'").replace(/[\n\r\t]/g, ' ').trim();
if (!prompt) throw new Error('veo3_prompt 없음 (장면2)');

return [{
  json: {
    veo3Body: {
      prompt: prompt,
      imageUrls: [frameUrl],
      model: 'veo3_fast',
      generationType: 'FIRST_AND_LAST_FRAMES_2_VIDEO',
      aspect_ratio: '16:9',
      enableTranslation: false
    }
  }
}];

