return [{ json: { frameUrl: frameUrl } }];

// 영상3 준비: 프레임2 결과에서 프레임 URL 가져오기
const frameUrl = $input.first().json.frameUrl || '';
if (!frameUrl) throw new Error('프레임2 URL 없음');

const seg = $('세그먼트 분리').all()[2].json;
