// 이미지 URL 추출 (폴링 포함)
const helpers = this.helpers;
const data = $input.first().json;
const KIE_KEY = '6c34c79064e71366c0fe9db193754999';

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

let imageUrl = '';

// 1) 이미 완료된 경우 바로 추출
if (data?.data?.state === 'success' && data?.data?.resultJson) {
  try {
    const parsed = JSON.parse(data.data.resultJson);
    imageUrl = (parsed.resultUrls || parsed.originUrls || [])[0] || '';
  } catch(e) {}
}

// 2) 미완료 시 폴링 (30초 간격, 최대 15분)
if (!imageUrl) {
  const taskId = data?.data?.taskId || $('이미지 생성').first().json?.data?.taskId || '';
  if (!taskId) throw new Error('taskId 없음: ' + JSON.stringify(data).substring(0, 300));

  for (let attempt = 0; attempt < 30; attempt++) {
    await sleep(30000);

    let resp;
    try {
      resp = await helpers.httpRequest({
        method: 'GET',
        url: 'https://api.kie.ai/api/v1/jobs/recordInfo?taskId=' + taskId,
        headers: { 'Authorization': 'Bearer ' + KIE_KEY }
      });
    } catch(e) {
      continue; // 네트워크 오류는 재시도
    }

    if (resp?.data?.state === 'success' && resp?.data?.resultJson) {
      try {
        const parsed = JSON.parse(resp.data.resultJson);
        imageUrl = (parsed.resultUrls || parsed.originUrls || [])[0] || '';
        if (imageUrl) break;
      } catch(e) {}
    }
    if (resp?.data?.state === 'failed') {
      throw new Error('이미지 생성 실패: ' + taskId);
    }
    // waiting, queuing, generating → 계속 대기
  }
}

if (!imageUrl) {
  throw new Error('이미지 URL 추출 실패 (15분 타임아웃)');
}

return [{
  json: {
    ...data,
    images: [{ url: imageUrl }]
  }
}];

